-- @gate: add
-- Intent: ONE-SHOT archive of the portal's pre-warehouse KPI/CEO history tables
--         (MIRROR-COVERAGE-AUDIT 2026-07-09 §2, gap #4): cm_total + cm_individual
--         (daily/monthly CM KPI history Oct-2025 -> May-2026 — the warehouse's own
--         history does not reach back that far) and the dormant CEO-dashboard
--         snapshot set (ceo_snapshot incl. financials, ceo_meetings,
--         ceo_infra_snapshot). If the portal dies, this history is otherwise gone.
-- Depends on: none
--
-- ADDITIVE ONLY: five new raw_portal_archive_* tables, data inlined. No recurring
-- sync — the source tables are dormant (cm_* and ceo_snapshot/ceo_meetings stopped
-- updating ~2026-06-14; ceo_infra_snapshot is a warehouse-DERIVED 1-row cache that
-- still refreshes, archived here once for completeness per the audit fold-in).
-- ceo_partner_meetings (0 rows live 2026-07-09) is skipped — nothing to archive.
--
-- Inline VALUES (not read_csv_auto): the PR gate rejects SQL referencing local
-- filesystem paths (same pattern as 1089_load_raw_partner_outcomes.sql), and
-- inlining makes the archive land in git AND self-heal onto MotherDuck via DDL
-- replay. core.schema_version guarantees this file applies exactly ONCE per
-- database, so the INSERTs cannot double-load.
--
-- Snapshot pulled 2026-07-09 via PostgREST (service key by name); all literals are
-- constants (no now()) so droplet and MotherDuck copies are byte-identical.
-- Source column names/types from the live PostgREST OpenAPI spec. cm_total.date /
-- cm_total.day are archived VERBATIM (junk JS date strings — fidelity over polish).

-- portal.cm_total (243 rows archived)
CREATE TABLE IF NOT EXISTS raw_portal_archive_cm_total (
    id                          BIGINT,
    year                        VARCHAR,
    date                        VARCHAR,
    day                         VARCHAR,
    inboxes                     DOUBLE,
    non_ai_emails_sent          VARCHAR,
    non_ai_meetings_booked      DOUBLE,
    ai_emails_sent              VARCHAR,
    ai_meetings_booked          DOUBLE,
    non_ai_sent_booked          DOUBLE,
    ai_sent_booked              DOUBLE,
    total_emails_sent           VARCHAR,
    total_meetings_booked       DOUBLE,
    sent_booked                 DOUBLE,
    _snapshot_date              DATE        NOT NULL,
    _source                     VARCHAR     NOT NULL,
    _loaded_at                  TIMESTAMPTZ NOT NULL
);


-- portal.cm_individual (84 rows archived)
CREATE TABLE IF NOT EXISTS raw_portal_archive_cm_individual (
    id                          BIGINT,
    year                        VARCHAR,
    month                       VARCHAR,
    campaign_manager            VARCHAR,
    inboxes                     DOUBLE,
    non_ai_emails_sent          VARCHAR,
    non_ai_meetings_booked      DOUBLE,
    ai_emails_sent              VARCHAR,
    ai_meetings_booked          DOUBLE,
    non_ai_sent_booked          DOUBLE,
    ai_sent_booked              DOUBLE,
    total_emails_sent           VARCHAR,
    total_meetings_booked       DOUBLE,
    sent_booked                 DOUBLE,
    all_time_meetings_booked    DOUBLE,
    all_time_ai_meetings_booked DOUBLE,
    _snapshot_date              DATE        NOT NULL,
    _source                     VARCHAR     NOT NULL,
    _loaded_at                  TIMESTAMPTZ NOT NULL
);


-- portal.ceo_snapshot (4 rows archived)
CREATE TABLE IF NOT EXISTS raw_portal_archive_ceo_snapshot (
    id                          INTEGER,
    date                        DATE,
    updated_at                  TIMESTAMPTZ,
    funding_sent                BIGINT,
    s125_sent                   BIGINT,
    tariffs_sent                BIGINT,
    rd_preipo_sent              BIGINT,
    yday_funding_sent           BIGINT,
    yday_s125_sent              BIGINT,
    yday_tariffs_sent           BIGINT,
    yday_rd_preipo_sent         BIGINT,
    mtd_booked                  INTEGER,
    yday_booked                 INTEGER,
    bank_checking               DECIMAL(18,2),
    bank_savings                DECIMAL(18,2),
    accounts_receivable         DECIMAL(18,2),
    accounts_payable            DECIMAL(18,2),
    mtd_revenue                 DECIMAL(18,2),
    _snapshot_date              DATE        NOT NULL,
    _source                     VARCHAR     NOT NULL,
    _loaded_at                  TIMESTAMPTZ NOT NULL
);


-- portal.ceo_meetings (86 rows archived)
CREATE TABLE IF NOT EXISTS raw_portal_archive_ceo_meetings (
    id                          INTEGER,
    date                        DATE,
    channel                     VARCHAR,
    offer                       VARCHAR,
    partner                     VARCHAR,
    count                       INTEGER,
    updated_at                  TIMESTAMPTZ,
    _snapshot_date              DATE        NOT NULL,
    _source                     VARCHAR     NOT NULL,
    _loaded_at                  TIMESTAMPTZ NOT NULL
);


-- portal.ceo_infra_snapshot (1 rows archived)
CREATE TABLE IF NOT EXISTS raw_portal_archive_ceo_infra_snapshot (
    id                          INTEGER,
    synced_at                   TIMESTAMPTZ,
    warehouse_snapshot_id       VARCHAR,
    google_active               INTEGER,
    otd_active                  INTEGER,
    microsoft_active            INTEGER,
    other_active                INTEGER,
    accounts_active             INTEGER,
    accounts_paused             INTEGER,
    accounts_error              INTEGER,
    emails_sent_mtd             BIGINT,
    emails_sent_yesterday       BIGINT,
    emails_sent_date            DATE,
    warehouse_max_date          DATE,
    _snapshot_date              DATE        NOT NULL,
    _source                     VARCHAR     NOT NULL,
    _loaded_at                  TIMESTAMPTZ NOT NULL
);

